blocks.body:
{
    "level": "B2–C1",
    "intro": "W tym temacie dowiesz się <strong>zaawansowanego wykorzystania rodzajników</strong> do uogólnień – jak mówić o <strong>całej klasie/kategorii</strong> przedmioty lub ludzie.",
    "rules": [
        {
            "label": "THE + przymiotnik",
            "color": "purple",
            "text": "<strong>+przymiotnik</strong> = grupa ludzi:",
            "example": "bogaci, biedni, młodzi, starsi"
        },
        {
            "label": "A/AN + liczba pojedyncza",
            "color": "blue",
            "text": "<strong>A/An + liczba pojedyncza</strong> = cały gatunek (formalnie):",
            "example": "Tygrys to niebezpieczne zwierzę."
        },
        {
            "label": "Ř + liczba mnoga",
            "color": "emerald",
            "text": "<strong>Brak przedimka + liczba mnoga</strong> = in general:",
            "example": "Tygrysy są niebezpieczne. / Ludzie potrzebują miłości."
        }
    ]
}

{
    "title": "1. Co to jest odniesienie ogólne?",
    "intro": "Odniesienie ogólne to uogólniające odniesienie do całej klasy lub kategorii:",
    "items": [
        {
            "label": "THE + adj",
            "title": "Grupa ludzi oparta na charakterystyce",
            "subtitle": "bogatych, biednych, niewidomych – wszyscy bogaci, wszyscy biedny"
        },
        {
            "label": "A + liczba pojedyncza",
            "title": "Przedstawiciel gatunku",
            "subtitle": "Tygrys poluje nocą - tygrys (jako gatunek) poluje nocą"
        },
        {
            "label": "Ř + liczba mnoga",
            "title": "Wszystkie przedstawiciele",
            "subtitle": "Tygrysy polują nocą – tygrysy (ogólnie) polują nocą"
        }
    ]
}

{
    "title": "2. THE + przymiotnik = grupa ludzi",
    "sections": [
        {
            "label": "Podstawowa zasada",
            "color": "purple",
            "description": "<strong>Przymiotnik +</strong> oznacza <strong>wszystkich ludzi z tą funkcją</strong> (liczba mnoga).",
            "examples": [
                {
                    "en": "bogaci = wszyscy bogaci ludzie",
                    "ua": "wszyscy bogaci ludzie"
                },
                {
                    "en": "biedni = wszyscy biedni ludzie",
                    "ua": "wszyscy biedni люди"
                },
                {
                    "en": "młodzi = wszyscy młodzi ludzie",
                    "ua": "wszyscy młodzi ludzie"
                },
                {
                    "en": "starsi = wszyscy starsi ludzie",
                    "ua": "wszyscy starsi ludzie"
                }
            ]
        },
        {
            "label": "W zdaniach",
            "color": "blue",
            "description": "Przykłady użycia <strong>przymiotnik +</strong>:",
            "examples": [
                {
                    "en": "Bogaci stają się bogatsi.",
                    "ua": "Bogaci stają się bogatsi."
                },
                {
                    "en": "Biedni potrzebują pomocy.",
                    "ua": "Biedni potrzebują pomocy."
                },
                {
                    "en": "Młodzi często buntownik.",
                    "ua": " buntownik."
                },
                {
                    "en": "Społeczeństwo musi chronić bezbronnych.",
                    "ua": "Społeczeństwo musi chronić bezbronnych."
                }
            ]
        },
        {
            "label": "Popularne przykłady",
            "color": "sky",
            "description": "Najczęstsze konstrukcje:",
            "examples": [
                {
                    "en": "bogaci / biedni / zamożni",
                    "ua": "młodzi / starzy / starsi"
                },
                {
                    "en": "the young / the old / the elderly",
                    "ua": "niewidomi / głusi / niepełnosprawni"
                },
                {
                    "en": "the blind / the deaf / the disabled",
                    "ua": " przez niepełnosprawność"
                },
                {
                    "en": "bezrobotni / niepełnosprawni bezdomny",
                    "ua": "небромы / недомы"
                }
            ],
            "note": "⚠️ Czasownik jest zawsze <strong>liczba mnoga</strong>: Bogaci <strong>są</strong> stają się bogatsi."
        }
    ]
}

{
    "title": "3. + narodowość",
    "sections": [
        {
            "label": "Zakończenie -ese, -ss, -sh, -ch",
            "color": "amber",
            "description": "<strong>+ narodowość</strong> w -ese, -ss, -sh, -ch = wszyscy przedstawiciele narodu.",
            "examples": [
                {
                    "en": "Chińczycy = wszyscy Chińczycy",
                    "ua": "wszyscy Chińczycy"
                },
                {
                    "en": "Japończycy = wszyscy Japończycy",
                    "ua": "wszyscy Japończycy"
                },
                {
                    "en": "Szwajcarzy = wszyscy Szwajcarzy",
                    "ua": "wszyscy Szwajcarzy"
                },
                {
                    "en": "Brytyjczycy = wszyscy Brytyjczycy",
                    "ua": "wszyscy Brytyjczycy"
                },
                {
                    "en": "Francuzi = wszyscy Francuzi",
                    "ua": "wszyscy Francuski"
                }
            ]
        },
        {
            "label": "U w zdaniach",
            "color": "purple",
            "description": "Przykłady użycia:",
            "examples": [
                {
                    "en": "Japończycy są znani ze swojej uprzejmości.",
                    "ua": "Japończycy są znani ze swojej uprzejmości."
                },
                {
                    "en": "Brytyjczycy kochają herbata.",
                    "ua": "Brytyjczycy uwielbiają herbatę."
                },
                {
                    "en": "Francuzi cenią sztukę i kulturę.",
                    "ua": "Francuzi cenią sztukę i kulturę."
                }
            ]
        },
        {
            "label": "Inne narodowości",
            "color": "sky",
            "description": "Narody z inną końcówką — <strong>bez</strong>, w liczbie mnogiej:",
            "examples": [
                {
                    "en": "Ukraińcy (nie Ukraińcy)",
                    "ua": "Ukraińcy"
                },
                {
                    "en": "Amerykanie, Niemcy, Włosi",
                    "ua": "Amerykanie, Niemcy, Włosi"
                }
            ],
            "note": "📌 <strong>The + -ese/-ss/-sh/-ch</strong>, inne to tylko liczba mnoga."
        }
    ]
}

{
    "title": "4. A/AN + liczba pojedyncza = cały gatunek (formalnie)",
    "sections": [
        {
            "label": "Przedstawiciel gatunku",
            "color": "blue",
            "description": "<strong>A/An + liczba pojedyncza</strong> może oznaczać <strong>cały gatunek</strong> (bardziej formalnie).",
            "examples": [
                {
                    "en": "Tygrys to niebezpieczne zwierzę.",
                    "ua": "Tygrys (jako gatunek) jest zwierzęciem niebezpiecznym."
                },
                {
                    "en": "Komputer może przechowywać dane.",
                    "ua": "Komputer (jako urządzenie) może przechowywać dane."
                },
                {
                    "en": "Pies jest lojalny wobec swojego właściciela.",
                    "ua": "Pies jest (ogólnie) lojalny wobec swojego właściciela."
                }
            ]
        },
        {
            "label": "Kiedy używać",
            "color": "purple",
            "description": "Używane w <strong>definicjach naukowych teksty, opisy formalne</strong>.",
            "examples": [
                {
                    "en": "Wieloryb to ssak, a nie ryba.",
                    "ua": "Wieloryb to ssak, a nie ryba."
                },
                {
                    "en": "Trójkąt ma trzy boki.",
                    "ua": "Trójkąt ma trzy boki."
                },
                {
                    "en": "Atom składa się z protonów, neutronów i elektronów.",
                    "ua": "Atom składa się z protonów, neutronów i elektronów."
                }
            ]
        },
        {
            "label": "Porównanie z liczbą mnogą",
            "color": "sky",
            "description": "Różnica między a/an a liczbą mnogą:",
            "examples": [
                {
                    "en": "Tygrys jest niebezpieczny. (formalny)",
                    "ua": "Tygrys jest niebezpieczny. (formalny)"
                },
                {
                    "en": "Tygrysy są niebezpieczne. (neutralny)",
                    "ua": "Tygrysy są niebezpieczne. (neutralny)"
                }
            ],
            "note": "📌 Obie opcje są poprawne, ale <strong>a/an</strong> jest bardziej formalne."
        }
    ]
}

{
    "title": "5. Ø + liczba mnoga = ogólnie (neutralny)",
    "sections": [
        {
            "label": "Ogólne znaczenie",
            "color": "emerald",
            "description": "<strong>Brak przedimka + liczba mnoga</strong> to najczęstsza metoda uogólniania.",
            "examples": [
                {
                    "en": "Tygrysy są niebezpieczne.",
                    "ua": "Tygrysy są niebezpieczne. (ogólnie wszystkie tygrysy)"
                },
                {
                    "en": "Ludzie potrzebują miłości.",
                    "ua": "Ludzie potrzebują miłości."
                },
                {
                    "en": "Psy to lojalne zwierzęta.",
                    "ua": "Psy to lojalne zwierzęta."
                },
                {
                    "en": "Książki są źródłem wiedzy wiedza.",
                    "ua": "Książki są źródłem wiedzy."
                }
            ]
        },
        {
            "label": "Najczęstsza opcja",
            "color": "sky",
            "description": "W języku potocznym i neutralnym liczba mnoga najczęściej nie zawiera przedimka.",
            "examples": [
                {
                    "en": "Komputery ułatwiają życie.",
                    "ua": "Komputery ułatwiają życie."
                },
                {
                    "en": "Dzieci potrzebują edukacji.",
                    "ua": "Dzieci potrzebują edukacja."
                },
                {
                    "en": "Naukowcy badają przyrodę.",
                    "ua": "Naukowcy badają przyrodę."
                }
            ]
        }
    ]
}

{
    "title": "6. + liczba pojedyncza = cały gatunek (rzadko)",
    "sections": [
        {
            "label": "Wyjątkowe wyjątki",
            "color": "rose",
            "description": "<strong>+ liczba pojedyncza</strong> jest rzadka, ale może oznaczać cały gatunek (bardzo formalnie).",
            "examples": [
                {
                    "en": "Tygrys to niebezpieczne zwierzę.",
                    "ua": "Tygrys (jako gatunek) jest niebezpieczny zwierzę."
                },
                {
                    "en": "Komputer zmienił nasze życie.",
                    "ua": "Komputer (jako wynalazek) zmienił nasze życie."
                }
            ]
        },
        {
            "label": "Kiedy jest używany",
            "color": "amber",
            "description": "Tylko w <strong>bardzo formalnych</strong> kontekstach lub w kontekście historycznym opisy.",
            "examples": [
                {
                    "en": "Telefon zrewolucjonizował komunikację.",
                    "ua": "Telefon zrewolucjonizował komunikację."
                },
                {
                    "en": "Dinozaur wyginął miliony lat temu.",
                    "ua": "Dinozaur wymarł miliony lat temu."
                }
            ],
            "note": "📌 Rzadką opcją jest użyć liczby mnogiej lub a/an."
        }
    ]
}

{
    "title": "7. Inne konstrukcje uogólniające",
    "sections": [
        {
            "label": "THE + stopień najwyższy",
            "color": "purple",
            "description": "<strong>+najwyższy stopień</strong> uogólnień.",
            "examples": [
                {
                    "en": "Najlepsze rzeczy w życiu są za darmo.",
                    "ua": "Najlepsze rzeczy w życiu są za darmo."
                },
                {
                    "en": "The najważniejsze jest zdrowie.",
                    "ua": "Najważniejsze jest zdrowie."
                }
            ]
        },
        {
            "label": "THE + only/main/same",
            "color": "blue",
            "description": "З певними прикметниками завжди <strong>the</strong>.",
            "examples": [
                {
                    "en": "The only solution is to try harder.",
                    "ua": "Єдиний вихід — старатися більше."
                },
                {
                    "en": "The main problem is lack of time.",
                    "ua": "Głównym problemem jest brak czasu."
                },
                {
                    "en": "Mamy to samo zdanie.",
                    "ua": "Mamy to samo zdanie."
                }
            ]
        }
    ]
}

{
    "title": "8. Tabela porównawcza uogólnień",
    "intro": "Różne sposoby przekazywania ogólnych odniesień:",
    "rows": [
        {
            "en": "THE + przymiotnik",
            "ua": "Grupa ludzi według cechy",
            "note": "bogaci, biedni, młodzi (liczba mnoga znaczenie)"
        },
        {
            "en": "THE + narodowość (-ese/-sh/-ch)",
            "ua": "Wszyscy przedstawiciele narodu",
            "note": "Chińczycy, Brytyjczycy, Francuzi"
        },
        {
            "en": "A/AN + liczba pojedyncza",
            "ua": "Wszystkie gatunki (formalny)",
            "note": "Tygrys jest niebezpieczny. (formalna definicja)"
        },
        {
            "en": "Ř + liczba mnoga",
            "ua": "Cały gatunek (neutralny)",
            "note": "Tygrysy są niebezpieczne. (najczęściej)"
        },
        {
            "en": "THE + liczba pojedyncza",
            "ua": "Cały gatunek (bardzo formalny)",
            "note": "Tygrys jest niebezpieczny. (rzadko, bardzo formalnie)"
        }
    ],
    "warning": "📌 Najpopularniejszym wariantem jest <strong>liczba mnoga bez przedimka</strong>. <strong>A/an + liczba pojedyncza</strong> jest formalna. <strong>Liczba pojedyncza +</strong> jest rzadka."
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Czasownik w liczbie pojedynczej z przymiotnikiem +.",
            "wrong": "Bogaci stają się coraz bogatsi.[[[CODX_30]]]​​​​ <span class="font-mono">Bogaci stają się coraz bogatsi. (liczba mnoga!)</span>",
            "right": "✅ <span class="font-mono">The rich are getting richer. (plural!)</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Przed zwykłym obywatelstwem.",
            "wrong": "Ukraińcy są przyjaźni.",
            "right": "​​​​ <span class="font-mono">Ukraińcy są przyjaźni. (bez)</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Artykuł w oświadczeniu ogólnym.",
            "wrong": "Tygrysy są niebezpieczne. (ogólnie wszystkie tygrysy)",
            "right": "​​​​ <span class="font-mono">Tygrysy są niebezpieczne. (bez)</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Zły wybór formy.",
            "wrong": "Tygrys jest niebezpieczny. (bez przedimka w liczbie pojedynczej)",
            "right": "​​​​ <span class="font-mono">Tygrys jest niebezpieczny. / Tygrysy są niebezpieczne.</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz poprawną formę uogólnienia.",
    "selects": [
        {
            "label": "___ potrzebuję edukacji. (Dzieci / Dzieci)",
            "prompt": "Która opcja?"
        },
        {
            "label": "___ stają się coraz bogatsi. (Bogaty / Bogaty)",
            "prompt": "Która opcja?"
        },
        {
            "label": "___ to niebezpieczne zwierzę. (Tygrys / Tygrys)",
            "prompt": "Która opcja?"
        },
        {
            "label": "___ są znani z uprzejmości. (japoński / japoński)",
            "prompt": "Która opcja?"
        }
    ],
    "options": [
        "Pierwsza opcja",
        "Druga opcja"
    ],
    "input_title": "Ćwiczenie 2. Wypełnij puste miejsca",
    "input_intro": "Wpisz poprawną formę (the, a lub Ø).",
    "inputs": [
        {
            "before": "___ biedni potrzebują pomocy.",
            "after": " →"
        },
        {
            "before": "___ komputer zmienił nasze życie.",
            "after": "→[[CODX_SEG_16]]]___ psy są lojalne zwierzęta."
        },
        {
            "before": "___ dogs are loyal animals.",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błędy",
    "rephrase_intro": "Znajdź i popraw błąd w zdaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Bogaci się bogacą bogatsi.",
            "example_target": "Bogaci stają się coraz bogatsi."
        },
        {
            "original": "1. Tygrysy to niebezpieczne zwierzęta. (oświadczenie ogólne)",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Ukraińcy to życzliwi ludzie. Artykuły",
            "placeholder": "Виправ помилку"
        }
    ]
}

{
    "title": "Інші сторінки з категорії Іменники, артиклі та кількість",
    "items": [
        {
            "label": "Advanced articles — узагальнення (поточна)",
            "current": true
        },
        {
            "label": "Articles with geographical names",
            "current": false
        },
        {
            "label": "Articles A / An / The — Артиклі",
            "current": false
        },
        {
            "label": "Artykuł zerowy — Artykuł zerowy",
            "current": false
        }
    ]
}
